class Solution:
    def stringIndices(self, wordsContainer: List[str], wordsQuery: List[str]) -> List[int]:
        from collections import defaultdict

        # Preprocess wordsContainer to map suffixes to the best candidate
        suffix_map = defaultdict(lambda: (float('inf'), float('inf'), -1))  # (length, index, original index)
        for idx, word in enumerate(wordsContainer):
            length = len(word)
            for i in range(1, length + 1):
                suffix = word[-i:]
                current_length, _, current_idx = suffix_map[suffix]
                if length < current_length or (length == current_length and idx < current_idx):
                    suffix_map[suffix] = (length, idx, idx)

        ans = []
        for query in wordsQuery:
            max_suffix = ""
            for i in range(1, len(query) + 1):
                suffix = query[-i:]
                if suffix in suffix_map:
                    length, _, idx = suffix_map[suffix]
                    if i > len(max_suffix):
                        max_suffix = suffix
                        best_length, best_idx = length, idx
                    elif i == len(max_suffix):
                        if length < best_length or (length == best_length and idx < best_idx):
                            best_length, best_idx = length, idx
            ans.append(best_idx)
        return ans
